                    { q: "Who was the mother of Hazrat Abu Bakr (RA)?", options: ["Salma bint Sakhar (Umm-ul-Khair)", "Fatima bint Asad", "Hind bint Utbah", "Umm Ruman"], answer: 0, explanation: "Umm-ul-Khair Salma bint Sakhar (RA) was his mother." },
                    { q: "Which Caliph's conversion gave great strength to the early Muslims in Makkah?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar's (RA) acceptance of Islam allowed Muslims to pray openly." },
                    { q: "Who was the first person to call Hazrat Abu Bakr 'As-Siddiq'?", options: ["Prophet Muhammad (PBUH)", "Hazrat Gabriel", "The Quraish", "Hazrat Aisha"], answer: 0, explanation: "The Prophet (PBUH) titled him As-Siddiq after the Isra and Mi'raj." },
                    { q: "During whose caliphate was the expansion into India initiated?", options: ["Hazrat Umar", "Hazrat Usman", "Hazrat Ali", "Hazrat Muawiyah"], answer: 1, explanation: "Initial coastal raids and expeditions happened during the time of Hazrat Usman (RA)." },
                    { q: "What was the name of the sword given to Hazrat Ali (RA) by the Prophet (PBUH)?", options: ["Al-Battar", "Dhulfiqar", "Al-Ma'thur", "Al-Qadib"], answer: 1, explanation: "Dhulfiqar is the famous double-pointed sword of Hazrat Ali (RA)." },
                    { q: "Who was the judge (Qadi) appointed by Hazrat Umar in Kufa?", options: ["Shurayh al-Qadi", "Abu Hanifa", "Ibn Abbas", "Zaid bin Thabit"], answer: 0, explanation: "Shurayh was a famous judge appointed by Hazrat Umar (RA)." },
                    { q: "Which Caliph was known as 'Ghani' (The Wealthy) for his generosity?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 2, explanation: "Hazrat Usman (RA) used his vast wealth to serve Islam." },
                    { q: "How many verses were revealed in favor of Hazrat Umar's suggestions (Muwafaqat-e-Umar)?", options: ["3", "12", "15", "More than 20"], answer: 3, explanation: "Several Quranic verses were revealed confirming Hazrat Umar's opinions." },
                    { q: "Who was the assassin of Hazrat Ali (RA)?", options: ["Abu Lu'lu'a", "Abdur Rahman ibn Muljam", "Ibn Mujashi", "Marwan"], answer: 1, explanation: "Ibn Muljam, a Kharijite, martyred Hazrat Ali (RA) in Kufa." },
                    { q: "Which Caliph founded the city of Fustat in Egypt?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Fustat was founded on the orders of Hazrat Umar (RA) by Amr bin al-Aas (RA)." },
                    { q: "Who was the only Caliph to be born inside the Kaaba?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 3, explanation: "Hazrat Ali (RA) was born inside the Holy Kaaba." },
                    { q: "Which Caliph was martyred while performing Fajr prayer?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) was stabbed while leading the congregation." },
                    { q: "Which Caliph was the last to be buried in the Prophet's Mosque?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "None"], answer: 1, explanation: "Only Abu Bakr and Umar (RA) are buried there." },
                    { q: "Who were the 'Ashara Mubashara'?", options: ["10 promised paradise", "10 writers of Quran", "10 warriors of Badr", "10 governors of Umar"], answer: 0, explanation: "Ten companions were given the glad tidings of Paradise in a single sitting." },
                    { q: "Which Caliph organized the first census of the Muslim population?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) introduced various statistical and administrative records." },
                    { q: "Who was the commander of the Muslim army in the Battle of Qadisiyah?", options: ["Sa'd bin Abi Waqqas", "Khalid bin Walid", "Amr bin al-Aas", "Abu Ubaidah"], answer: 0, explanation: "Sa'd bin Abi Waqqas (RA) led the victory against the Persians." },
                    { q: "Which Caliph had the longest reign among the Rashidun?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 2, explanation: "Hazrat Usman (RA) ruled for 12 years." },
                    { q: "Which Caliph had the shortest reign among the Rashidun?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 0, explanation: "Hazrat Abu Bakr (RA) ruled for about 2 years and 3 months." },
                    { q: "Who succeeded Hazrat Ali (RA) as Caliph for a brief period before resigning?", options: ["Hazrat Hasan (RA)", "Hazrat Hussain (RA)", "Amir Muawiyah", "Abdullah bin Zubair"], answer: 0, explanation: "Hazrat Hasan (RA) ruled for about 6 months before making peace." },
                    { q: "Which Caliph was known for his 'Zuhd' (Asceticism) even while being a ruler?", options: ["All of them", "Only Hazrat Ali", "Only Hazrat Umar", "Only Hazrat Abu Bakr"], answer: 0, explanation: "All Rashidun caliphs lived extremely simple lives." },
                    { q: "Who was the 'Secretary of the State' during Hazrat Abu Bakr's caliphate?", options: ["Hazrat Usman", "Hazrat Ali", "Hazrat Umar", "Zaid bin Thabit"], answer: 3, explanation: "Zaid bin Thabit (RA) handled much of the official correspondence." },
                    { q: "Which Caliph introduced the 'Ushr' (10% tax on trade)?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) introduced customs duties on international trade." },
                    { q: "Which Caliph’s daughter was married to the Prophet (PBUH)?", options: ["Hazrat Abu Bakr and Hazrat Umar", "Hazrat Usman", "Hazrat Ali", "None"], answer: 0, explanation: "Hazrat Aisha (daughter of Abu Bakr) and Hazrat Hafsa (daughter of Umar) were wives of the Prophet (PBUH)." },
                    { q: "Who was the first person to accept Islam among women?", options: ["Hazrat Khadija", "Hazrat Aisha", "Hazrat Fatima", "Hazrat Sumayyah"], answer: 0, explanation: "Hazrat Khadija (RA) was the first believer." },
                    { q: "Which Caliph was known as 'Siddiq-e-Akbar'?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 0, explanation: "It means 'The Greatest Truthful'." },
                    { q: "Who defeated Musaylimah the Liar?", options: ["Khalid bin Walid", "Abu Bakr", "Zaid bin Harith", "Ikrimah"], answer: 0, explanation: "The Battle of Yamama was won under the leadership of Khalid bin Walid." },
                    { q: "During whose caliphate did the Battle of Camel take place?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 3, explanation: "The Battle of Jamal (36 AH) was fought during Hazrat Ali's (RA) time." },
                    { q: "Who were the 'Abadilah' (The Four Abdullahs)?", options: ["Famous scholars among Sahaba", "A military group", "The four caliphs", "A tribe"], answer: 0, explanation: "Abdullah bin Abbas, Abdullah bin Umar, Abdullah bin Amr, and Abdullah bin Zubair." },
                    { q: "Which Caliph was famous for his nightly rounds to check on citizens?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) used to patrol the streets of Madinah in disguise." },
                    { q: "Who was the first governor of Kufa?", options: ["Sa'd bin Abi Waqqas", "Amr bin al-Aas", "Muawiyah", "Abu Musa al-Ashari"], answer: 0, explanation: "Sa'd bin Abi Waqqas (RA) was the first governor." },
                    { q: "Which Caliph sent 12,000 troops to help Amr bin al-Aas in Egypt?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) sent reinforcements to complete the conquest." },
                    { q: "What was the name of the valley where Hazrat Umar used to graze camels in his youth?", options: ["Dajnan", "Arafat", "Mina", "Badr"], answer: 0, explanation: "He often mentioned Dajnan with humility regarding his past." },
                    { q: "Who was the first Muslim to be called 'Amir-ul-Momineen'?", options: ["Hazrat Abu Bakr", "Hazrat Umar", "Hazrat Usman", "Hazrat Ali"], answer: 1, explanation: "Hazrat Umar (RA) was the first to adopt this title formally." },
                    { q: "Where is Hazrat Ali (RA) buried?", options: ["Najaf", "Kufa", "Madinah", "Kerbala"], answer: 0, explanation: "His tomb is in Imam Ali Mosque, Najaf, Iraq." },
                    { q: "Which Caliph was known for his beautiful handwriting and was a scribe of the Quran?", options: ["Hazrat Usman", "Hazrat Ali", "Both", "None"], answer: 2, explanation: "Both Hazrat Usman and Hazrat Ali (RA) were prominent scribes." },
                    { q: "Who advised Hazrat Abu Bakr (RA) to compile the Quran?", options: ["Hazrat Umar", "Hazrat Ali", "Hazrat Usman", "Hazrat Aisha"], answer: 0, explanation: "Hazrat Umar (RA) suggested it after the martyrdom of many Hufaaz in Yamama." },
                    { q: "In which year did Hazrat Abu Bakr (RA) become Caliph?", options: ["10 AH", "11 AH", "12 AH", "13 AH"], answer: 1, explanation: "He was elected in 11 AH (632 AD)." },
                    { q: "Who was the father of Hazrat Umar (RA)?", options: ["Khattab", "Nufayl", "Abdul Muttalib", "Abu Sufyan"], answer: 0, explanation: "Al-Khattab ibn Nufayl was his father." },
                    { q: "Which Caliph established the first naval station at Cyprus?", options: ["Hazrat Umar", "Hazrat Usman", "Hazrat Ali", "Muawiyah"], answer: 1, explanation: "The conquest of Cyprus occurred during Hazrat Usman's (RA) reign." },
                    { q: "Which companion was nicknamed 'The Trusted One of this Ummah'?", options: ["Abu Ubaidah bin al-Jarrah", "Abu Bakr", "Umar", "Usman"], answer: 0, explanation: "The Prophet (PBUH) called him Ameen-ul-Ummah." },
                    { q: "How many times is the word 'Caliph' (Khalifa) mentioned in the Quran in singular form?", options: ["1", "2", "5", "10"], answer: 1, explanation: "It is mentioned twice, referring to Adam (AS) and Dawud (AS)." },
                    { q: "Who was the mother of Hazrat Usman (RA)?", options: ["Arwa bint Kurayz", "Fatima bint Asad", "Hind", "Umm Ruman"], answer: 0, explanation: "Arwa bint Kurayz (RA) was his mother." },
                    { q: "Which Caliph was known as 'Asadullah' (Lion of Allah)?", options: ["Hazrat Ali", "Hazrat Hamza", "Both", "None"], answer: 2, explanation: "Both Hazrat Ali and Hazrat Hamza (RA) held this title." },
                    { q: "Who was the commander who conquered Persia for Hazrat Umar?", options: ["Sa'd bin Abi Waqqas", "Khalid bin Walid", "Musa bin Nusayr", "Tariq bin Ziyad"], answer: 0, explanation: "Sa'd bin Abi Waqqas (RA) won the battle of Qadisiyah." },
                    { q: "Which Caliph had the title 'Zun-Nurain'?", options: ["Hazrat Usman", "Hazrat Ali", "Hazrat Abu Bakr", "Hazrat Umar"], answer: 0, explanation: "Possessor of Two Lights (marrying two daughters of the Prophet)." },
                    { q: "At what age was Hazrat Ali (RA) martyred?", options: ["60", "63", "65", "50"], answer: 1, explanation: "He was martyred at the age of 63 in 40 AH." }
